@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments</PageTitle>

<h1>Shipments</h1>

<button class="btn btn-primary mb-3" @onclick="ShowCreateForm">+ New Shipment</button>

@if (showCreateForm)
{
    <div class="card mb-3 p-3">
        <h4>Create Shipment</h4>
        <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="CreateShipment">
            <DataAnnotationsValidator />
            <div class="row g-2 mb-2">
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <InputText class="form-control" @bind-Value="newShipment.Origin" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <InputText class="form-control" @bind-Value="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Customer Email</label>
                    <InputText class="form-control" @bind-Value="newShipment.CustomerEmail" />
                </div>
            </div>
            <div class="mb-2">
                <label class="form-label">Description</label>
                <InputText class="form-control" @bind-Value="newShipment.Description" />
            </div>
            <button type="submit" class="btn btn-success me-2">Create</button>
            <button type="button" class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
        </EditForm>
    </div>
}

@if (shipments == null)
{
    <p>Loading shipments...</p>
}
else if (!shipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-2">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">
                            @shipment.Status
                        </span>
                    </td>
                    <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@((int)shipment.Status)"
                                @onchange="e => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@((int)status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private Shipment newShipment = new();
    private bool showCreateForm;
    private string filterText = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        newShipment = new Shipment();
        showCreateForm = true;
    }

    private async Task CreateShipment()
    {
        await ShipmentService.CreateShipmentAsync(newShipment);
        shipments = await ShipmentService.GetAllShipmentsAsync();
        showCreateForm = false;
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusInt))
        {
            var newStatus = (ShipmentStatus)statusInt;
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.InTransit => "bg-info",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment == null)
