arguments.new_str:
builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();

builder.Services.AddScoped<IShipmentService, ServerShipmentService>();

var app = builder.Build();

// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

// Shipment API endpoints
var shipmentApi = app.MapGroup("api/shipments").RequireAuthorization();

shipmentApi.MapGet("", async (IShipmentService service) =>
    Results.Ok(await service.GetAllShipmentsAsync()));

shipmentApi.MapGet("track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
{
    var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
});

shipmentApi.MapPost("", async (Shipment shipment, IShipmentService service) =>
{
    var created = await service.CreateShipmentAsync(shipment);
    return Results.Created($"api/shipments/track/{created.TrackingNumber}", created);
});

shipmentApi.MapPut("{id}/status", async (int id, ShipmentStatus status, IShipmentService service) =>
{
    await service.UpdateShipmentStatusAsync(id, status);
    return Results.NoContent();
});

app.Run();

